import{_ as a,o as r,c as e,a2 as l}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 步兵陣地戰完全指南：扛住就是勝利","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/infantry-warfare.md","filePath":"bannerlord/infantry-warfare.md"}'),d={name:"bannerlord/infantry-warfare.md"};function i(o,t,h,n,s,c){return r(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="騎砍2-步兵陣地戰完全指南-扛住就是勝利" tabindex="-1">騎砍2 | 步兵陣地戰完全指南：扛住就是勝利 <a class="header-anchor" href="#騎砍2-步兵陣地戰完全指南-扛住就是勝利" aria-label="Permalink to &quot;騎砍2 | 步兵陣地戰完全指南：扛住就是勝利&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>步兵是每支軍隊的脊樑。沒有步兵扛線，你的弓兵會被騎兵輾過去，你的騎兵衝鋒完沒人補位。這篇講怎麼讓你的步兵變成一座移動要塞。</p><hr><h2 id="一、步兵的定位" tabindex="-1">一、步兵的定位 <a class="header-anchor" href="#一、步兵的定位" aria-label="Permalink to &quot;一、步兵的定位&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>說明</th></tr></thead><tbody><tr><td>扛線</td><td>擋住敵方步兵和騎兵衝鋒</td></tr><tr><td>保護</td><td>站在弓兵和弩手前面</td></tr><tr><td>推進</td><td>攻城時推塔、破門、巷戰</td></tr><tr><td>補位</td><td>騎兵衝完拉走後，步兵填上去</td></tr></tbody></table><hr><h2 id="二、各國步兵排名" tabindex="-1">二、各國步兵排名 <a class="header-anchor" href="#二、各國步兵排名" aria-label="Permalink to &quot;二、各國步兵排名&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">排名</th><th>兵種</th><th>國家</th><th>特色</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td>帝國軍團步兵</td><td>帝國</td><td>最全面，能扛能打</td></tr><tr><td style="text-align:center;">2</td><td>斯特吉亞重裝斧兵</td><td>斯特吉亞</td><td>傷害最高，攻城無敵</td></tr><tr><td style="text-align:center;">3</td><td>瓦蘭迪亞長矛兵</td><td>瓦蘭迪亞</td><td>反騎最強，但對步兵弱</td></tr><tr><td style="text-align:center;">4</td><td>阿塞萊步兵</td><td>阿塞萊</td><td>標槍很痛，但防禦較低</td></tr></tbody></table><hr><h2 id="三、陣型與戰術" tabindex="-1">三、陣型與戰術 <a class="header-anchor" href="#三、陣型與戰術" aria-label="Permalink to &quot;三、陣型與戰術&quot;">​</a></h2><h3 id="_3-1-盾牆陣-f3-f2" tabindex="-1">3.1 盾牆陣（F3+F2） <a class="header-anchor" href="#_3-1-盾牆陣-f3-f2" aria-label="Permalink to &quot;3.1 盾牆陣（F3+F2）&quot;">​</a></h3><p>最常用的防禦陣型。步兵舉盾靠攏：</p><ul><li>正面防禦力極高</li><li>騎兵衝不過去</li><li>缺點：移動很慢、側面和背後脆弱</li></ul><h3 id="_3-2-方陣-f3-f3" tabindex="-1">3.2 方陣（F3+F3） <a class="header-anchor" href="#_3-2-方陣-f3-f3" aria-label="Permalink to &quot;3.2 方陣（F3+F3）&quot;">​</a></h3><p>對抗騎兵的最佳陣型。四面都有盾牌：</p><ul><li>騎兵從哪個方向衝都會撞上盾牌</li><li>但弓兵能射到你</li><li>只在被騎兵包圍時用</li></ul><h3 id="_3-3-戰術流程" tabindex="-1">3.3 戰術流程 <a class="header-anchor" href="#_3-3-戰術流程" aria-label="Permalink to &quot;3.3 戰術流程&quot;">​</a></h3><ol><li>步兵 F3+F2 排盾牆在最前面</li><li>弓兵在步兵後方高處</li><li>騎兵在側翼待命</li><li>敵方接近 → 騎兵側面衝鋒</li><li>騎兵拉走 → 步兵推進收割</li></ol><hr><h2 id="四、反騎兵技巧" tabindex="-1">四、反騎兵技巧 <a class="header-anchor" href="#四、反騎兵技巧" aria-label="Permalink to &quot;四、反騎兵技巧&quot;">​</a></h2><p>騎兵衝鋒是步兵最大的威脅。應對方法：</p><ol><li><strong>長矛/長桿武器</strong>：瓦蘭迪亞長矛兵專門反騎</li><li><strong>盾牆陣</strong>：騎兵衝不穿密集盾牆</li><li><strong>地形</strong>：森林、橋樑、狹窄地形 = 騎兵廢掉</li><li><strong>圍毆</strong>：騎兵停下來後讓步兵圍上去</li></ol><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./troop-tier-list.html">騎砍2 | 兵種大亂鬥</a></li><li><a href="./combat-tactics.html">騎砍2 | 戰鬥技巧完全指南</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',32)])])}const u=a(d,[["render",i]]);export{b as __pageData,u as default};
